class Solution:
    def simplifyPath(self, path: str) -> str:
        stack = deque()

        for ch in path.split('/'):
            match ch:
                case ''| '.':
                    continue
                case '..':
                    if stack:
                        stack.pop()
                case _:
                    stack.append(ch)

        return "/" + "/".join(stack)
